import hashlib
import time
import logging
from dataclasses import dataclass, field
from typing import Optional

log = logging.getLogger(__name__)


@dataclass
class FilterResult:
    blocked: bool
    reason: Optional[str] = None
    stage: Optional[str] = None
    score: float = 0.0
    metadata: dict = field(default_factory=dict)


class MLSafetyClassifier:
    """Wraps a safety classification model."""

    def __init__(self, threshold: float = 0.80):
        self.threshold = threshold
        self._cache: dict[str, float] = {}

    def _hash(self, text: str) -> str:
        return hashlib.sha256(text.encode()).hexdigest()

    def score(self, text: str) -> float:
        """Return a harm probability in [0, 1]. Replace stub with real model."""
        key = self._hash(text)
        if key in self._cache:
            return self._cache[key]
        # Stub: real implementations call openai.moderations.create() or similar
        score = 0.05
        lower = text.lower()
        if "jailbreak" in lower or "bypass" in lower or "dan mode" in lower:
            score = 0.93
        self._cache[key] = score
        return score

    def evaluate(self, prompt: str) -> FilterResult:
        s = self.score(prompt)
        if s >= self.threshold:
            return FilterResult(
                blocked=True, reason="ml_high_risk_score", stage="ml", score=s
            )
        return FilterResult(blocked=False, stage="ml", score=s)


class PolicyEngine:
    """Stage 3: rate limits and business rules."""

    def __init__(self, max_per_minute: int = 20, max_prompt_chars: int = 8000):
        self.max_per_minute = max_per_minute
        self.max_chars = max_prompt_chars
        self._buckets: dict[str, list[float]] = {}

    def _check_rate(self, user_id: str) -> bool:
        now = time.time()
        bucket = self._buckets.setdefault(user_id, [])
        self._buckets[user_id] = [t for t in bucket if now - t < 60]
        if len(self._buckets[user_id]) >= self.max_per_minute:
            return False
        self._buckets[user_id].append(now)
        return True

    def evaluate(self, prompt: str, user_id: str, role: str) -> FilterResult:
        if not self._check_rate(user_id):
            return FilterResult(
                blocked=True, reason="rate_limit_exceeded", stage="policy"
            )
        if len(prompt) > self.max_chars:
            return FilterResult(
                blocked=True, reason="prompt_too_long", stage="policy"
            )
        return FilterResult(blocked=False, stage="policy")


class PromptFilterPipeline:
    def __init__(self, keyword_filter, ml_classifier, policy_engine):
        self._stages = [
            ("keyword", lambda p, ctx: keyword_filter.evaluate(p)),
            ("ml",      lambda p, ctx: ml_classifier.evaluate(p)),
            ("policy",  lambda p, ctx: policy_engine.evaluate(
                p, ctx["user_id"], ctx.get("role", "user")
            )),
        ]

    def run(self, prompt: str, context: dict) -> FilterResult:
        t0 = time.perf_counter()
        outcome = FilterResult(blocked=False)
        for name, evaluator in self._stages:
            result = evaluator(prompt, context)
            result.stage = name
            if result.blocked:
                outcome = result
                break
        latency_ms = round((time.perf_counter() - t0) * 1000, 2)
        log.info(
            "filter_decision",
            extra={
                "prompt_hash": hashlib.sha256(prompt.encode()).hexdigest()[:16],
                "user_id": context.get("user_id"),
                "blocked": outcome.blocked,
                "reason": outcome.reason,
                "stage": outcome.stage,
                "latency_ms": latency_ms,
            },
        )
        return outcome


