import re
from dataclasses import dataclass
from typing import Optional

# PII detection patterns for the legal assistant
PII_PATTERNS = [
    r"\b\d{3}-\d{2}-\d{4}\b",                              # SSN
    r"\b(?:\d[ -]?){13,16}\b",                               # credit card (rough)
    r"\b[A-Z][a-z]+ [A-Z][a-z]+,? DOB \d{2}/\d{2}/\d{4}\b",  # Name + DOB combo
]

OFF_TOPIC_KEYWORDS = [
    "personal injury lawsuit against us",
    "our billing rate",
    "CompetitorFirm",
]

SEALED_CASE_ROLES = {"senior_partner", "managing_partner"}


@dataclass
class FilterResult:
    blocked: bool
    reason: Optional[str] = None


def legal_assistant_filter(prompt: str, user_context: dict) -> FilterResult:
    # Stage 1a: PII detection
    for pattern in PII_PATTERNS:
        if re.search(pattern, prompt, re.IGNORECASE):
            return FilterResult(
                blocked=True,
                reason="pii_detected_please_redact_before_submitting",
            )

    # Stage 1b: Off-topic keyword check
    lower = prompt.lower()
    for kw in OFF_TOPIC_KEYWORDS:
        if kw.lower() in lower:
            return FilterResult(
                blocked=True,
                reason="off_topic_request_not_supported",
            )

    # Stage 2: Length cap (prevent context stuffing)
    if len(prompt.split()) > 1000:
        return FilterResult(blocked=True, reason="prompt_exceeds_word_limit")

    # Stage 3: Role-based access for sealed cases
    mentions_sealed = "sealed" in lower or "in camera" in lower
    if mentions_sealed and user_context.get("role") not in SEALED_CASE_ROLES:
        return FilterResult(
            blocked=True,
            reason="sealed_case_access_restricted_to_senior_partners",
        )

    return FilterResult(blocked=False)


# Test: associate asking about sealed case
result = legal_assistant_filter(
    prompt="What can you tell me about the sealed settlement in Smith v Jones?",
    user_context={"user_id": "atty_45", "role": "associate"},
)
print(result)
